EntityListener = {}

function EntityListener:init()
    BaseListener.registerCallBack(SpawnEntityEvent, self.onSpawnEntity)

    Listener.registerCallBack(AttackActorNpcEvent, self.AttackActorNpc)
    Listener.registerCallBack(CreatureAttackCreatureEvent, self.onCreatureAttackCreature)
    Listener.registerCallBack(CreatureAttackPlayerEvent, self.onCreatureAttackCreature)
end

function EntityListener.AttackActorNpc(entityId)
    AreaManager:actorClicked(entityId, GamePlayer:Instance())
    return false
end

function EntityListener.onCreatureAttackCreature(targetId, throwerId)
    local area = AreaManager:getAreaByEntityId(throwerId)
    if area and area.__cname == "TowerArea" then
        area:bulletAttack(targetId)
    end
end

function EntityListener.onSpawnEntity(lEntity)
    -----可视距离调整
    if lEntity.type == 50 then
        lEntity.entity:setIgnoreFrustumCheck(true)
        lEntity.entity:setRenderDistanceWeight(5)
    end
end